var surah037 = {
  number: 37,
  nameArabic: "As-Saffat",
  nameEnglish: "As-Saffat",
  meaning: "Those Who Set The Ranks",
  totalAyahs: 182,
  ayahs: [
    { number: 1, arabic: "وَٱلصَّٰٓفَّٰتِ صَفًّۭا", transliteration: "Waalssaffati saffan", transliterationB: "Wassaaaffaati saffaa", english: "By those who range themselves in ranks", romanUrdu: "Qataar dar qataar saff baandhne walon ki kasam" },
    { number: 2, arabic: "فَٱلزَّٰجِرَٰتِ زَجْرًۭا", transliteration: "Faalzzajirati zajran", transliterationB: "Fazzaajiraati zajraa", english: "And so are strong in repelling (evil)", romanUrdu: "Phir unki kasam jo daatne phatkaar ne waley hain" },
    { number: 3, arabic: "فَٱلتَّٰلِيَٰتِ ذِكْرًا", transliteration: "Faalttaliyati thikran", transliterationB: "Fattaaliyaati Zikra", english: "And thus proclaim the Message (of Allah)", romanUrdu: "Phir unki kasam jo kalaam e naseehat sunane waley hain" },
    { number: 4, arabic: "إِنَّ إِلَٰهَكُمْ لَوَٰحِدٌۭ", transliteration: "Inna ilahakum lawahidun", transliterationB: "Inna Illaahakum la Waahid", english: "Verily, verily, your Allah is one", romanUrdu: "Tumhara mabood e haqiqi bas ek hi hai" },
    { number: 5, arabic: "رَّبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا وَرَبُّ ٱلْمَشَٰرِقِ", transliteration: "Rabbu alssamawati waalardi wama baynahuma warabbu almashariqi", transliterationB: "Rabbus samaawaati wal ardi wa maa bainahumaa wa Rabbul mashaariq", english: "Lord of the heavens and of the earth and all between them, and Lord of every point at the rising of the sun", romanUrdu: "Woh jo zameen aur aasmaano ka aur tamaam un cheezon ka maalik hai jo zameen o aasmaan mein hain, aur saarey mashrikon(easts) ka maalik" },
    { number: 6, arabic: "إِنَّا زَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِزِينَةٍ ٱلْكَوَاكِبِ", transliteration: "Inna zayyanna alssamaa alddunya bizeenatin alkawakibi", transliterationB: "Innaa zaiyannas samaaa 'ad dunyaa bizeenatinil kawaakib", english: "We have indeed decked the lower heaven with beauty (in) the stars", romanUrdu: "Humne aasmaan e duniya ko taaron ki zeenat se aarasta (adorn) kiya hai" },
    { number: 7, arabic: "وَحِفْظًۭا مِّن كُلِّ شَيْطَٰنٍۢ مَّارِدٍۢ", transliteration: "Wahifthan min kulli shaytanin maridin", transliterationB: "Wa hifzam min kulli Shaitaanim maarid", english: "(For beauty) and for guard against all obstinate rebellious evil spirits", romanUrdu: "Aur har shaytan sarkash se isko mehfooz kardiya hai" },
    { number: 8, arabic: "لَّا يَسَّمَّعُونَ إِلَى ٱلْمَلَإِ ٱلْأَعْلَىٰ وَيُقْذَفُونَ مِن كُلِّ جَانِبٍۢ", transliteration: "La yassammaAAoona ila almalai alaAAla wayuqthafoona min kulli janibin", transliterationB: "Laa yassamma 'oona ilal mala il a'alaa wa yuqzafoona min kulli jaanib", english: "(So) they should not strain their ears in the direction of the Exalted Assembly but be cast away from every side", romanUrdu: "Yeh shayateen mala-e-aala (High Council) ki baatein nahin sun saktey, har taraf se maarey aur haankey jatey hain" },
    { number: 9, arabic: "دُحُورًۭا ۖ وَلَهُمْ عَذَابٌۭ وَاصِبٌ", transliteration: "Duhooran walahum AAathabun wasibun", transliterationB: "Duhooranw wa lahum 'azaabunw waasib", english: "Repulsed, for they are under a perpetual penalty", romanUrdu: "Aur inke liye paiham azaaab hai" },
    { number: 10, arabic: "إِلَّا مَنْ خَطِفَ ٱلْخَطْفَةَ فَأَتْبَعَهُۥ شِهَابٌۭ ثَاقِبٌۭ", transliteration: "Illa man khatifa alkhatfata faatbaAAahu shihabun thaqibun", transliterationB: "Illaa man khatifal khatfata fa atba'ahoo shihaabun saaqib", english: "Except such as snatch away something by stealth, and they are pursued by a flaming fire, of piercing brightness", romanUrdu: "Taaham agar koi inmein se kuch ley uday to ek teiz shola uska peecha karta hai" },
    { number: 11, arabic: "فَٱسْتَفْتِهِمْ أَهُمْ أَشَدُّ خَلْقًا أَم مَّنْ خَلَقْنَآ ۚ إِنَّا خَلَقْنَٰهُم مِّن طِينٍۢ لَّازِبٍۭ", transliteration: "Faistaftihim ahum ashaddu khalqan am man khalaqna inna khalaqnahum min teenin lazibin", transliterationB: "Fastaftihim ahum ashaddu khalqan am man khalaqnaa; innaa khalaqnaahum min teenil laazib", english: "Just ask their opinion: are they the more difficult to create, or the (other) beings We have created? Them have We created out of a sticky clay", romanUrdu: "Ab insey pucho, inki paidaish zyada mushkil hai ya un cheezon ki jo humne paida kar rakkhi hain? Inko to humne leis daar gaaray(sticky clay/chickni mitti) se paida kiya hai" },
    { number: 12, arabic: "بَلْ عَجِبْتَ وَيَسْخَرُونَ", transliteration: "Bal AAajibta wayaskharoona", transliterationB: "Bal'ajibta wa yaskharoon", english: "Truly dost thou marvel, while they ridicule", romanUrdu: "Tum (Allah ki qudrat ke karishmon par) hairan ho aur yeh iska mazaak uda rahey hain" },
    { number: 13, arabic: "وَإِذَا ذُكِّرُوا۟ لَا يَذْكُرُونَ", transliteration: "Waitha thukkiroo la yathkuroona", transliterationB: "Wa izaa zukkiroo laa yazkuroon", english: "And, when they are admonished, pay no heed", romanUrdu: "Samjhaya jaata hai to samajh kar nahin detey" },
    { number: 14, arabic: "وَإِذَا رَأَوْا۟ ءَايَةًۭ يَسْتَسْخِرُونَ", transliteration: "Waitha raaw ayatan yastaskhiroona", transliterationB: "Wa izaa ra aw Aayatinw yastaskhiroon", english: "And, when they see a Sign, turn it to mockery", romanUrdu: "Koi nishani dekhte hain to usey thatton (mazaak/mock) mein udatey hain" },
    { number: 15, arabic: "وَقَالُوٓا۟ إِنْ هَٰذَآ إِلَّا سِحْرٌۭ مُّبِينٌ", transliteration: "Waqaloo in hatha illa sihrun mubeenun", transliterationB: "Wa qaalooo in haazaa illaa sihrum mubeen", english: "And say, \"This is nothing but evident sorcery", romanUrdu: "Aur kehte hain “ yeh to sareeh jaadu hai" },
    { number: 16, arabic: "أَءِذَا مِتْنَا وَكُنَّا تُرَابًۭا وَعِظَٰمًا أَءِنَّا لَمَبْعُوثُونَ", transliteration: "Aitha mitna wakunna turaban waAAithaman ainna lamabAAoothoona", transliterationB: "A-izaa mitnaa wa kunnaa turaabanw wa 'izaaman 'ainnaa lamab'oosoon", english: "What! when we die, and become dust and bones, shall we (then) be raised up (again)", romanUrdu: "Bhala kahin aisa ho sakta hai ke jab hum mar chuke hon aur mitti ban jayein aur haddiyon ka panjar reh jaye us waqt hum phir zinda karke utha khade kiye jayein" },
    { number: 17, arabic: "أَوَءَابَآؤُنَا ٱلْأَوَّلُونَ", transliteration: "Awaabaona alawwaloona", transliterationB: "Awa aabaa'unal awwaloon", english: "And also our fathers of old", romanUrdu: "Aur kya hamare agle waqton ke aaba o ajdaad bhi uthaye jayenge?”" },
    { number: 18, arabic: "قُلْ نَعَمْ وَأَنتُمْ دَٰخِرُونَ", transliteration: "Qul naAAam waantum dakhiroona", transliterationB: "Qul na'am wa antum daakhiroon", english: "Say thou: \"Yea, and ye shall then be humiliated (on account of your evil)", romanUrdu: "(insey kaho haan, aur tum) khuda ke muqable mein baybas ho" },
    { number: 19, arabic: "فَإِنَّمَا هِىَ زَجْرَةٌۭ وَٰحِدَةٌۭ فَإِذَا هُمْ يَنظُرُونَ", transliteration: "Fainnama hiya zajratun wahidatun faitha hum yanthuroona", transliterationB: "Fa innamaa hiya zajra tunw waahidatun fa izaa hum yanzuroon", english: "Then it will be a single (compelling) cry; and behold, they will begin to see", romanUrdu: "Bas ek hi jhidki hogi aur yakayak yeh apni aankhon se (woh sab kuch jiski khabar di jaa rahi hai) dekh rahey hongey" },
    { number: 20, arabic: "وَقَالُوا۟ يَٰوَيْلَنَا هَٰذَا يَوْمُ ٱلدِّينِ", transliteration: "Waqaloo ya waylana hatha yawmu alddeeni", transliterationB: "Qa qaaloo yaa wailanaa haazaa Yawmud-Deen", english: "They will say, \"Ah! Woe to us! This is the Day of Judgment", romanUrdu: "Us waqt yeh kahengey “ haaye hamari kambakhti , yeh to yaum ul jaza hai”" },
    { number: 21, arabic: "هَٰذَا يَوْمُ ٱلْفَصْلِ ٱلَّذِى كُنتُم بِهِۦ تُكَذِّبُونَ", transliteration: "Hatha yawmu alfasli allathee kuntum bihi tukaththiboona", transliterationB: "Haazaa Yawmul Faslil lazee kuntum bihee tukaziboon", english: "(A voice will say,) \"This is the Day of Sorting Out, whose truth ye (once) denied", romanUrdu: "“yeh wahi faisley ka din hai jisey tum jhutlaya karte thay”" },
    { number: 22, arabic: "۞ ٱحْشُرُوا۟ ٱلَّذِينَ ظَلَمُوا۟ وَأَزْوَٰجَهُمْ وَمَا كَانُوا۟ يَعْبُدُونَ", transliteration: "Ohshuroo allatheena thalamoo waazwajahum wama kanoo yaAAbudoona", transliterationB: "Uhshurul lazeena zalamoo wa azwaajahum wa maa kaanoo ya'budoon", english: "Bring ye up\", it shall be said, \"The wrong-doers and their wives, and the things they worshipped", romanUrdu: "(Hukum hoga) gher lao sab zaalimon aur unke saathiyon aur un maboodon ko jinki woh khuda ko chodh kar bandagi kiya karte thay" },
    { number: 23, arabic: "مِن دُونِ ٱللَّهِ فَٱهْدُوهُمْ إِلَىٰ صِرَٰطِ ٱلْجَحِيمِ", transliteration: "Min dooni Allahi faihdoohum ila sirati aljaheemi", transliterationB: "Min doonil laahi fahdoohum ilaa siraatil Jaheem", english: "Besides Allah, and lead them to the Way to the (Fierce) Fire", romanUrdu: "Phir un sab ko jahannum ka raasta dikhao" },
    { number: 24, arabic: "وَقِفُوهُمْ ۖ إِنَّهُم مَّسْـُٔولُونَ", transliteration: "Waqifoohum innahum masooloona", transliterationB: "Wa qifoohum innahum mas'ooloon", english: "But stop them, for they must be asked", romanUrdu: "Aur zara inhein thehrao, inse kuch puchna hai" },
    { number: 25, arabic: "مَا لَكُمْ لَا تَنَاصَرُونَ", transliteration: "Ma lakum la tanasaroona", transliterationB: "Maa lakum laa tanaasaroon", english: "What is the matter with you that ye help not each other", romanUrdu: "“Kya ho gaya tumhein, ab kyun ek dusre ki madad nahin karte" },
    { number: 26, arabic: "بَلْ هُمُ ٱلْيَوْمَ مُسْتَسْلِمُونَ", transliteration: "Bal humu alyawma mustaslimoona", transliterationB: "Bal humul Yawma mustaslimoon", english: "Nay, but that day they shall submit (to Judgment)", romanUrdu: "(Arey, aaj to yeh apne aap ko) aur ek dusre ko hawaliye (surrender) kiye de rahe hain”" },
    { number: 27, arabic: "وَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍۢ يَتَسَآءَلُونَ", transliteration: "Waaqbala baAAduhum AAala baAAdin yatasaaloona", transliterationB: "Wa aqbala ba'duhum 'alaa ba'diny yatasaaa'aloon", english: "And they will turn to one another, and question one another", romanUrdu: "Iske baad yeh ek dusre ki taraf mudenge aur baham takrar shuru kar dengey" },
    { number: 28, arabic: "قَالُوٓا۟ إِنَّكُمْ كُنتُمْ تَأْتُونَنَا عَنِ ٱلْيَمِينِ", transliteration: "Qaloo innakum kuntum tatoonana AAani alyameeni", transliterationB: "Qaalooo innakum kuntum taatoonanaa 'anil yameen", english: "They will say: \"It was ye who used to come to us from the right hand (of power and authority)", romanUrdu: "pairvi karne waley apne peshwaon[leaders] se) kahenge, “Tum hamare paas seedhay rukh se aate thay”" },
    { number: 29, arabic: "قَالُوا۟ بَل لَّمْ تَكُونُوا۟ مُؤْمِنِينَ", transliteration: "Qaloo bal lam takoonoo mumineena", transliterationB: "Qaaloo bal lam takoonoo mu'mineen", english: "They will reply: \"Nay, ye yourselves had no Faith", romanUrdu: "Woh jawaab dengey “nahin balke tum khud iman laney waley na thay" },
    { number: 30, arabic: "وَمَا كَانَ لَنَا عَلَيْكُم مِّن سُلْطَٰنٍۭ ۖ بَلْ كُنتُمْ قَوْمًۭا طَٰغِينَ", transliteration: "Wama kana lana AAalaykum min sultanin bal kuntum qawman tagheena", transliterationB: "Wa maa kaana lanaa 'alaikum min sultaanim bal kuntum qawman taagheen", english: "Nor had we any authority over you. Nay, it was ye who were a people in obstinate rebellion", romanUrdu: "Hamara tumpar koi zoar na tha, tum khud hi sarkash log thay" },
    { number: 31, arabic: "فَحَقَّ عَلَيْنَا قَوْلُ رَبِّنَآ ۖ إِنَّا لَذَآئِقُونَ", transliteration: "Fahaqqa AAalayna qawlu rabbina inna lathaiqoona", transliterationB: "Fahaqqa 'alainaa qawlu Rabbinaaa innaa lazaaa'iqoon", english: "So now has been proved true, against us, the word of our Lord that we shall indeed (have to) taste (the punishment of our sins)", romanUrdu: "Aakhir e kaar hum apne Rubb ke is farmaan ke mustahiq ho gaye ke hum azaab ka maza chakhne waley hain" },
    { number: 32, arabic: "فَأَغْوَيْنَٰكُمْ إِنَّا كُنَّا غَٰوِينَ", transliteration: "Faaghwaynakum inna kunna ghaweena", transliterationB: "Fa aghwainaakum innaa kunnaa ghaaween", english: "We led you astray: for truly we were ourselves astray", romanUrdu: "So humne tumko behkaya, hum khud behke huye thay”" },
    { number: 33, arabic: "فَإِنَّهُمْ يَوْمَئِذٍۢ فِى ٱلْعَذَابِ مُشْتَرِكُونَ", transliteration: "Fainnahum yawmaithin fee alAAathabi mushtarikoona", transliterationB: "Fa innahum Yawma'izin fil'azaabi mushtarikoon", english: "Truly, that Day, they will (all) share in the Penalty", romanUrdu: "Is taraah woh sab us roz azaab mein mushtarik (shareek) hongey" },
    { number: 34, arabic: "إِنَّا كَذَٰلِكَ نَفْعَلُ بِٱلْمُجْرِمِينَ", transliteration: "Inna kathalika nafAAalu bialmujrimeena", transliterationB: "Innaa kazaalika naf'alu bil mujrimeen", english: "Verily that is how We shall deal with Sinners", romanUrdu: "Hum mujreemon ke saath yahi kuch kiya karte hain" },
    { number: 35, arabic: "إِنَّهُمْ كَانُوٓا۟ إِذَا قِيلَ لَهُمْ لَآ إِلَٰهَ إِلَّا ٱللَّهُ يَسْتَكْبِرُونَ", transliteration: "Innahum kanoo itha qeela lahum la ilaha illa Allahu yastakbiroona", transliterationB: "Innahum kaanooo izaa qeela lahum laaa ilaaha illal laahu yastakbiroon", english: "For they, when they were told that there is no god except Allah, would puff themselves up with Pride", romanUrdu: "Yeh woh log thay ke jab unsey kaha jata “Allah ke siwa koi maabood e barhaqq nahin hai” to yeh ghamand mein aa jatey thay" },
    { number: 36, arabic: "وَيَقُولُونَ أَئِنَّا لَتَارِكُوٓا۟ ءَالِهَتِنَا لِشَاعِرٍۢ مَّجْنُونٍۭ", transliteration: "Wayaqooloona ainna latarikoo alihatina lishaAAirin majnoonin", transliterationB: "Wa yaqooloona a'innaa lataarikooo aalihatinaa lishaa'irim majnoon", english: "And say: \"What! shall we give up our gods for the sake of a Poet possessed", romanUrdu: "Aur kehte thay “kya hum ek shayar majnoon (dewane) ki khaatir apne maboodon ko chodh dein?”" },
    { number: 37, arabic: "بَلْ جَآءَ بِٱلْحَقِّ وَصَدَّقَ ٱلْمُرْسَلِينَ", transliteration: "Bal jaa bialhaqqi wasaddaqa almursaleena", transliterationB: "bal jaaa'a bilhaqqi wa saddaqal mursaleen", english: "Nay! he has come with the (very) Truth, and he confirms (the Message of) the messengers (before him)", romanUrdu: "Halaanke woh haqq lekar aaya tha aur usne Rasoolon ki tasdeeq ki thi" },
    { number: 38, arabic: "إِنَّكُمْ لَذَآئِقُوا۟ ٱلْعَذَابِ ٱلْأَلِيمِ", transliteration: "Innakum lathaiqoo alAAathabi alaleemi", transliterationB: "Innakum lazaaa'iqul 'azaabil aleem", english: "Ye shall indeed taste of the Grievous Penalty", romanUrdu: "(Ab unse kaha jayega ke) tum laaziman dardnaak saza ka maza chakhne waley ho" },
    { number: 39, arabic: "وَمَا تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Wama tujzawna illa ma kuntum taAAmaloona", transliterationB: "Wa maa tujzawna illaa maa kuntum ta'maloon", english: "But it will be no more than the retribution of (the Evil) that ye have wrought", romanUrdu: "Aur tumhein jo badla bhi diya jaa raha hai unhi aamaal ka diya ja raha hai jo tum karte rahey ho" },
    { number: 40, arabic: "إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ", transliteration: "Illa AAibada Allahi almukhlaseena", transliterationB: "Illaa 'ibaadal laahil mukhlaseen", english: "But the sincere (and devoted) Servants of Allah", romanUrdu: "Magar Allah ke cheeda (chune huey/chosen) banday (is anjaam e badd se) mehfooz hongey" },
    { number: 41, arabic: "أُو۟لَٰٓئِكَ لَهُمْ رِزْقٌۭ مَّعْلُومٌۭ", transliteration: "Olaika lahum rizqun maAAloomun", transliterationB: "Ulaaa'ika lahum rizqum ma'loom", english: "For them is a Sustenance determined", romanUrdu: "Unke liye jaana bujha rizq (known provision) hai" },
    { number: 42, arabic: "فَوَٰكِهُ ۖ وَهُم مُّكْرَمُونَ", transliteration: "Fawakihu wahum mukramoona", transliterationB: "Fa waakihu wa hum mukramoon", english: "Fruits (Delights); and they (shall enjoy) honour and dignity", romanUrdu: "Har tarah ki lazeez cheezein" },
    { number: 43, arabic: "فِى جَنَّٰتِ ٱلنَّعِيمِ", transliteration: "Fee jannati alnnaAAeemi", transliterationB: "Fee jannaatin Na'eem", english: "In Gardens of Felicity", romanUrdu: "Aur niyamat bhari jannatein" },
    { number: 44, arabic: "عَلَىٰ سُرُرٍۢ مُّتَقَٰبِلِينَ", transliteration: "AAala sururin mutaqabileena", transliterationB: "Alaa sururim mutaqaa bileen", english: "Facing each other on Thrones (of Dignity)", romanUrdu: "Jinmein woh izzat ke saath rakkhey jayenge, takhaton par aamne saamne baithenge" },
    { number: 45, arabic: "يُطَافُ عَلَيْهِم بِكَأْسٍۢ مِّن مَّعِينٍۭ", transliteration: "Yutafu AAalayhim bikasin min maAAeenin", transliterationB: "Yutaafu 'alaihim bikaasim mim ma'een", english: "Round will be passed to them a Cup from a clear-flowing fountain", romanUrdu: "Sharaab ke chamson (springs) se sagar (cups) bhar bhar kar unke darmiyan phiraye jayenge" },
    { number: 46, arabic: "بَيْضَآءَ لَذَّةٍۢ لِّلشَّٰرِبِينَ", transliteration: "Baydaa laththatin lilshsharibeena", transliterationB: "Baidaaa'a laz zatil lish shaaribeen", english: "Crystal-white, of a taste delicious to those who drink (thereof)", romanUrdu: "Chamakti hui sharaab, jo peene waalon ke liye lazzat hogi" },
    { number: 47, arabic: "لَا فِيهَا غَوْلٌۭ وَلَا هُمْ عَنْهَا يُنزَفُونَ", transliteration: "La feeha ghawlun wala hum AAanha yunzafoona", transliterationB: "Laa feehaa ghawlunw wa laa hum 'anhaa yunzafoon", english: "Free from headiness; nor will they suffer intoxication therefrom", romanUrdu: "Na unke jism ko ussey koi zarar hoga aur na unki aqal ussey kharab hogi" },
    { number: 48, arabic: "وَعِندَهُمْ قَٰصِرَٰتُ ٱلطَّرْفِ عِينٌۭ", transliteration: "WaAAindahum qasiratu alttarfi AAeenun", transliterationB: "Wa 'indahum qaasiraatut tarfi 'een", english: "And besides them will be chaste women, restraining their glances, with big eyes (of wonder and beauty)", romanUrdu: "Aur unke paas nigahein bachane wali, khoobsurat aankhon wali auratein hongi" },
    { number: 49, arabic: "كَأَنَّهُنَّ بَيْضٌۭ مَّكْنُونٌۭ", transliteration: "Kaannahunna baydun maknoonun", transliterationB: "Ka annahunna baidum maknoon", english: "As if they were (delicate) eggs closely guarded", romanUrdu: "Aisi naazuk jaise andey (egg) ke chilke ke nichey chupi hui jhilli" },
    { number: 50, arabic: "فَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍۢ يَتَسَآءَلُونَ", transliteration: "Faaqbala baAAduhum AAala baAAdin yatasaaloona", transliterationB: "Fa aqbala ba'duhum 'alaa badiny yatasaaa 'aloon", english: "Then they will turn to one another and question one another", romanUrdu: "Phir woh ek dusre ki taraf mutawajjeh ho kar halaat puchengey" },
    { number: 51, arabic: "قَالَ قَآئِلٌۭ مِّنْهُمْ إِنِّى كَانَ لِى قَرِينٌۭ", transliteration: "Qala qailun minhum innee kana lee qareenun", transliterationB: "Qaala qaaa'ilum minhum innee kaana lee qareen", english: "One of them will start the talk and say: \"I had an intimate companion (on the earth)", romanUrdu: "Unmein se ek kahega, “duniya mein mera ek hum nahseen (companion) tha" },
    { number: 52, arabic: "يَقُولُ أَءِنَّكَ لَمِنَ ٱلْمُصَدِّقِينَ", transliteration: "Yaqoolu ainnaka lamina almusaddiqeena", transliterationB: "Yaqoolu a'innnaka laminal musaddiqeen", english: "Who used to say, 'what! art thou amongst those who bear witness to the Truth (of the Message)", romanUrdu: "Jo mujhse kaha karta tha, kya tum bhi tasdeeq karne walon mein se ho" },
    { number: 53, arabic: "أَءِذَا مِتْنَا وَكُنَّا تُرَابًۭا وَعِظَٰمًا أَءِنَّا لَمَدِينُونَ", transliteration: "Aitha mitna wakunna turaban waAAithaman ainna lamadeenoona", transliterationB: "A-izaa mitnaa wa kunnaa turaabanw wa 'izaaman 'ainnaa lamadeenoon", english: "When we die and become dust and bones, shall we indeed receive rewards and punishments", romanUrdu: "Kya waqayi jab hum mar chuke hongey aur mitti ho jayenge aur haddiyon ka panjar bankar reh jayenge to humein jaza o saza di jayegi" },
    { number: 54, arabic: "قَالَ هَلْ أَنتُم مُّطَّلِعُونَ", transliteration: "Qala hal antum muttaliAAoona", transliterationB: "Qaala hal antum muttali'oon", english: "(A voice) said: \"Would ye like to look down", romanUrdu: "Ab kya aap log dekhna chahte hain ke woh sahib ab kahan hain?”" },
    { number: 55, arabic: "فَٱطَّلَعَ فَرَءَاهُ فِى سَوَآءِ ٱلْجَحِيمِ", transliteration: "FaittalaAAa faraahu fee sawai aljaheemi", transliterationB: "Fattala'a fara aahu fee sawaaa'il Jaheem", english: "He looked down and saw him in the midst of the Fire", romanUrdu: "Yeh keh kar junhi woh jhukega to jahannum ki gehrayi mein usko dekh lega" },
    { number: 56, arabic: "قَالَ تَٱللَّهِ إِن كِدتَّ لَتُرْدِينِ", transliteration: "Qala taAllahi in kidta laturdeeni", transliterationB: "Qaala tallaahi in kitta laturdeen", english: "He said: \"By Allah! thou wast little short of bringing me to perdition", romanUrdu: "Aur ussey khitaab karke kahega “khuda ki kasam, tu to mujhey tabaah hi kar dene wala tha" },
    { number: 57, arabic: "وَلَوْلَا نِعْمَةُ رَبِّى لَكُنتُ مِنَ ٱلْمُحْضَرِينَ", transliteration: "Walawla niAAmatu rabbee lakuntu mina almuhdareena", transliterationB: "Wa law laa ni'matu Rabbee lakuntu minal muhdareen", english: "Had it not been for the Grace of my Lord, I should certainly have been among those brought (there)", romanUrdu: "Mere Rubb ka fazal shamil e haal na hota to aaj main bhi un logon mein se hota jo pakde huey aaye hain" },
    { number: 58, arabic: "أَفَمَا نَحْنُ بِمَيِّتِينَ", transliteration: "Afama nahnu bimayyiteena", transliterationB: "Afamaa nahnu bimaiyiteen", english: "Is it (the case) that we shall not die", romanUrdu: "Accha to kya ab hum marne waley nahin hain" },
    { number: 59, arabic: "إِلَّا مَوْتَتَنَا ٱلْأُولَىٰ وَمَا نَحْنُ بِمُعَذَّبِينَ", transliteration: "Illa mawtatana aloola wama nahnu bimuAAaththabeena", transliterationB: "Illa mawtatanal oola wa maa nahnu bimu'azzabeen", english: "Except our first death, and that we shall not be punished", romanUrdu: "Maut jo humein aani thi woh bas pehle aa chuki? Ab humein koi azaab nahin hona?”" },
    { number: 60, arabic: "إِنَّ هَٰذَا لَهُوَ ٱلْفَوْزُ ٱلْعَظِيمُ", transliteration: "Inna hatha lahuwa alfawzu alAAatheemu", transliterationB: "Inna haazaa falya'ma lil'aamiloon", english: "Verily this is the supreme achievement", romanUrdu: "Yakeenan yahi azeem o shaan kaamiyabi hai" },
    { number: 61, arabic: "لِمِثْلِ هَٰذَا فَلْيَعْمَلِ ٱلْعَٰمِلُونَ", transliteration: "Limithli hatha falyaAAmali alAAamiloona", transliterationB: "Limisli haaza falya'ma lil 'aamiloon", english: "For the like of this let all strive, who wish to strive", romanUrdu: "Aisi hi kamiyabi ke liye amal karne walon ko amal karna chahiye" },
    { number: 62, arabic: "أَذَٰلِكَ خَيْرٌۭ نُّزُلًا أَمْ شَجَرَةُ ٱلزَّقُّومِ", transliteration: "Athalika khayrun nuzulan am shajaratu alzzaqqoomi", transliterationB: "Azaalika khairun nuzulan am shajaratuz Zaqqom", english: "Is that the better entertainment or the Tree of Zaqqum", romanUrdu: "Bolo, yeh ziyafat acchi hai ya zakkhum ka darakht" },
    { number: 63, arabic: "إِنَّا جَعَلْنَٰهَا فِتْنَةًۭ لِّلظَّٰلِمِينَ", transliteration: "Inna jaAAalnaha fitnatan lilththalimeena", transliterationB: "Innaa ja'alnaahaa fitnatal lizzaalimeen", english: "For We have truly made it (as) a trial for the wrong-doers", romanUrdu: "Humne us darakht ko zaalimon ke liye fitna bana diya hai" },
    { number: 64, arabic: "إِنَّهَا شَجَرَةٌۭ تَخْرُجُ فِىٓ أَصْلِ ٱلْجَحِيمِ", transliteration: "Innaha shajaratun takhruju fee asli aljaheemi", transliterationB: "Innahaa shajaratun takhruju feee aslil Jaheem", english: "For it is a tree that springs out of the bottom of Hell-Fire", romanUrdu: "Woh ek darakht hai jo jahannum ki teh se nikalta hai" },
    { number: 65, arabic: "طَلْعُهَا كَأَنَّهُۥ رُءُوسُ ٱلشَّيَٰطِينِ", transliteration: "TalAAuha kaannahu ruoosu alshshayateeni", transliterationB: "Tal'uhaa ka annahoo ru'oosush Shayaateen", english: "The shoots of its fruit-stalks are like the heads of devils", romanUrdu: "Uske shagufe (emerging fruit) aise hain jaise shaytano ke sar" },
    { number: 66, arabic: "فَإِنَّهُمْ لَءَاكِلُونَ مِنْهَا فَمَالِـُٔونَ مِنْهَا ٱلْبُطُونَ", transliteration: "Fainnahum laakiloona minha famalioona minha albutoona", transliterationB: "Fa innahum la aakiloona minhaa famaali'oona minhal butoon", english: "Truly they will eat thereof and fill their bellies therewith", romanUrdu: "Jahannum ke log usey khayenge aur usi se pait bharengey" },
    { number: 67, arabic: "ثُمَّ إِنَّ لَهُمْ عَلَيْهَا لَشَوْبًۭا مِّنْ حَمِيمٍۢ", transliteration: "Thumma inna lahum AAalayha lashawban min hameemin", transliterationB: "Summa inna lahum 'alaihaa lashawbam min hameem", english: "Then on top of that they will be given a mixture made of boiling water", romanUrdu: "Phir ispar peene ke liye khaulta hua pani milega" },
    { number: 68, arabic: "ثُمَّ إِنَّ مَرْجِعَهُمْ لَإِلَى ٱلْجَحِيمِ", transliteration: "Thumma inna marjiAAahum laila aljaheemi", transliterationB: "Summa inna marji'ahum la ilal Jaheem", english: "Then shall their return be to the (Blazing) Fire", romanUrdu: "Aur iske baad unki wapsi usi aatish e dozakh (blazing Hell) ki taraf hogi" },
    { number: 69, arabic: "إِنَّهُمْ أَلْفَوْا۟ ءَابَآءَهُمْ ضَآلِّينَ", transliteration: "Innahum alfaw abaahum dalleena", transliterationB: "Innahum alfaw aabaaa'ahum daaalleen", english: "Truly they found their fathers on the wrong Path", romanUrdu: "Yeh woh log hain jinhon ne apne baap dada ko gumraah paya" },
    { number: 70, arabic: "فَهُمْ عَلَىٰٓ ءَاثَٰرِهِمْ يُهْرَعُونَ", transliteration: "Fahum AAala atharihim yuhraAAoona", transliterationB: "Fahum 'alaa aasaarihim yuhra'oon", english: "So they (too) were rushed down on their footsteps", romanUrdu: "Aur unhi ke nakshe qadam par daud chale" },
    { number: 71, arabic: "وَلَقَدْ ضَلَّ قَبْلَهُمْ أَكْثَرُ ٱلْأَوَّلِينَ", transliteration: "Walaqad dalla qablahum aktharu alawwaleena", transliterationB: "Wa laqad dalla qablahum aksarul awwaleen", english: "And truly before them, many of the ancients went astray", romanUrdu: "Halaanke unse pehle bahut se log gumraah ho chuke thay" },
    { number: 72, arabic: "وَلَقَدْ أَرْسَلْنَا فِيهِم مُّنذِرِينَ", transliteration: "Walaqad arsalna feehim munthireena", transliterationB: "Wa laqad arsalnaa feehim munzireen", english: "But We sent aforetime, among them, (messengers) to admonish them", romanUrdu: "Aur unmein humne tambeeh (warn) karne walay Rasool bheje thay" },
    { number: 73, arabic: "فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُنذَرِينَ", transliteration: "Faonthur kayfa kana AAaqibatu almunthareena", transliterationB: "Fanzur kaifa kaana 'aaqibatul munzareen", english: "Then see what was the end of those who were admonished (but heeded not)", romanUrdu: "Ab dekhlo ke un tambeeh kiye janey walon ka kya anjaam hua" },
    { number: 74, arabic: "إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ", transliteration: "Illa AAibada Allahi almukhlaseena", transliterationB: "Illaa 'ibaadal laahil mukhlaseen", english: "Except the sincere (and devoted) Servants of Allah", romanUrdu: "Is bad-anjaami se bas Allah ke wahi banday bachay hain jinhein usne apne liye khalis karliya hai" },
    { number: 75, arabic: "وَلَقَدْ نَادَىٰنَا نُوحٌۭ فَلَنِعْمَ ٱلْمُجِيبُونَ", transliteration: "Walaqad nadana noohun falaniAAma almujeeboona", transliterationB: "Wa laqad naadaanaa Noohun falani'mal mujeeboon", english: "(In the days of old), Noah cried to Us, and We are the best to hear prayer", romanUrdu: "Humko (issey pehle) Nooh ne pukara tha, to dekho ke hum kaise acche jawab dene waley thay" },
    { number: 76, arabic: "وَنَجَّيْنَٰهُ وَأَهْلَهُۥ مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ", transliteration: "Wanajjaynahu waahlahu mina alkarbi alAAatheemi", transliterationB: "Wa jajainaahu wa ahlahoo minal karbil 'azeem", english: "And We delivered him and his people from the Great Calamity", romanUrdu: "Humne usko aur uske ghar walon ko karb-e-azeem (badi musibat) se bacha liya" },
    { number: 77, arabic: "وَجَعَلْنَا ذُرِّيَّتَهُۥ هُمُ ٱلْبَاقِينَ", transliteration: "WajaAAalna thurriyyatahu humu albaqeena", transliterationB: "Wa ja'alnaa zurriyyatahoo hummul baaqeen", english: "And made his progeny to endure (on this earth)", romanUrdu: "Aur usi ki nasal ko baaki rakkha" },
    { number: 78, arabic: "وَتَرَكْنَا عَلَيْهِ فِى ٱلْءَاخِرِينَ", transliteration: "Watarakna AAalayhi fee alakhireena", transliterationB: "Wa taraknaa 'alaihi fil aakhireen", english: "And We left (this blessing) for him among generations to come in later times", romanUrdu: "Aur baad ki nasalon mein iski taarif o tausif chodh di" },
    { number: 79, arabic: "سَلَٰمٌ عَلَىٰ نُوحٍۢ فِى ٱلْعَٰلَمِينَ", transliteration: "Salamun AAala noohin fee alAAalameena", transliterationB: "Salaamun 'alaa Noohin fil 'aalameen", english: "Peace and salutation to Noah among the nations", romanUrdu: "Salaam hai Nooh par tamaam duniya walon mein" },
    { number: 80, arabic: "إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Inna kathalika najzee almuhsineena", transliterationB: "Innaa kazaalika najzil muhsineen", english: "Thus indeed do we reward those who do right", romanUrdu: "Hum neki karne walon ko aisi hi jaza diya karte hain" },
    { number: 81, arabic: "إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ", transliteration: "Innahu min AAibadina almumineena", transliterationB: "Innahoo min 'ibaadinal mu'mineen", english: "For he was one of our believing Servants", romanUrdu: "Dar haqeeqat woh hamare momin bandon mein se tha" },
    { number: 82, arabic: "ثُمَّ أَغْرَقْنَا ٱلْءَاخَرِينَ", transliteration: "Thumma aghraqna alakhareena", transliterationB: "Summa aghraqnal aakhareen", english: "Then the rest we overwhelmed in the Flood", romanUrdu: "Phir dusre giroh ko humne garq (drown) kardiya" },
    { number: 83, arabic: "۞ وَإِنَّ مِن شِيعَتِهِۦ لَإِبْرَٰهِيمَ", transliteration: "Wainna min sheeAAatihi laibraheema", transliterationB: "Wa ina min shee'atihee la Ibraaheem", english: "Verily among those who followed his Way was Abraham", romanUrdu: "Aur Nooh hi ke tareeqey par chalne wala Ibrahim tha" },
    { number: 84, arabic: "إِذْ جَآءَ رَبَّهُۥ بِقَلْبٍۢ سَلِيمٍ", transliteration: "Ith jaa rabbahu biqalbin saleemin", transliterationB: "Iz jaaa'a Rabbahoo bi qalbin saleem", english: "Behold! he approached his Lord with a sound heart", romanUrdu: "Jab woh apne Rubb ke huzur qalb e saleem lekar aaya" },
    { number: 85, arabic: "إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَاذَا تَعْبُدُونَ", transliteration: "Ith qala liabeehi waqawmihi matha taAAbudoona", transliterationB: "Iz qaala li abeehi wa qawmihee maazaa ta'budoon", english: "Behold! he said to his father and to his people, \"What is that which ye worship", romanUrdu: "Jab usne apne baap aur apni qaum se kaha “yeh kya cheezein hain jinki tum ibadat kar rahey ho" },
    { number: 86, arabic: "أَئِفْكًا ءَالِهَةًۭ دُونَ ٱللَّهِ تُرِيدُونَ", transliteration: "Aifkan alihatan doona Allahi tureedoona", transliterationB: "A'ifkan aalihatan doonal laahi tureedoon", english: "Is it a falsehood- gods other than Allah- that ye desire", romanUrdu: "Kya Allah ko chodh kar jhoot ghadey huey maabood chahte ho" },
    { number: 87, arabic: "فَمَا ظَنُّكُم بِرَبِّ ٱلْعَٰلَمِينَ", transliteration: "Fama thannukum birabbi alAAalameena", transliterationB: "Famaa zannukum bi Rabbil'aalameen", english: "Then what is your idea about the Lord of the worlds", romanUrdu: "Aakhir Allah Rubb-ul-Aalameen ke baarey mein tumhara kya gumaan hai?”" },
    { number: 88, arabic: "فَنَظَرَ نَظْرَةًۭ فِى ٱلنُّجُومِ", transliteration: "Fanathara nathratan fee alnnujoomi", transliterationB: "Fanazara nazratan finnujoom", english: "Then did he cast a glance at the Stars", romanUrdu: "Phir usne taaron par ek nigaah daali" },
    { number: 89, arabic: "فَقَالَ إِنِّى سَقِيمٌۭ", transliteration: "Faqala innee saqeemun", transliterationB: "Faqaala inee saqeem", english: "And he said, \"I am indeed sick (at heart)", romanUrdu: "Aur kaha meri tabiyat kharaab hai" },
    { number: 90, arabic: "فَتَوَلَّوْا۟ عَنْهُ مُدْبِرِينَ", transliteration: "Fatawallaw AAanhu mudbireena", transliterationB: "Fatawallaw 'anhu mudbireen", english: "So they turned away from him, and departed", romanUrdu: "Chunanche woh log usey chodh kar chale gaye" },
    { number: 91, arabic: "فَرَاغَ إِلَىٰٓ ءَالِهَتِهِمْ فَقَالَ أَلَا تَأْكُلُونَ", transliteration: "Faragha ila alihatihim faqala ala takuloona", transliterationB: "Faraagha ilaaa aalihatihim faqaala alaa taakuloon", english: "Then did he turn to their gods and said, \"will ye not eat (of the offerings before you)", romanUrdu: "Unke peechey woh chupke se unke maboodon ke mandir mein ghus gaya aur bola “aap log khate kyun nahin hain" },
    { number: 92, arabic: "مَا لَكُمْ لَا تَنطِقُونَ", transliteration: "Ma lakum la tantiqoona", transliterationB: "Maa lakum laa tantiqoon", english: "What is the matter with you that ye speak not (intelligently)", romanUrdu: "Kya ho gaya, aap log bolte bhi nahin?”" },
    { number: 93, arabic: "فَرَاغَ عَلَيْهِمْ ضَرْبًۢا بِٱلْيَمِينِ", transliteration: "Faragha AAalayhim darban bialyameeni", transliterationB: "Faraagha 'alaihim darbam bilyameen", english: "Then did he turn upon them, striking (them) with the right hand", romanUrdu: "Iske baad woh unpar pil (toot) pada aur seedhay haath se khoob zarbein lagayi (todhna shuru kiya)" },
    { number: 94, arabic: "فَأَقْبَلُوٓا۟ إِلَيْهِ يَزِفُّونَ", transliteration: "Faaqbaloo ilayhi yaziffoona", transliterationB: "Fa aqbalooo ilaihi yaziffoon", english: "Then came (the worshippers) with hurried steps, and faced (him)", romanUrdu: "(Wapas aakar) woh log bhaage bhaage uske paas aaye" },
    { number: 95, arabic: "قَالَ أَتَعْبُدُونَ مَا تَنْحِتُونَ", transliteration: "Qala ataAAbudoona ma tanhitoona", transliterationB: "Qaala ata'budoona maa tanhitoon", english: "He said: \"Worship ye that which ye have (yourselves) carved", romanUrdu: "Usne kaha “kya tum apni hi tarashi hui cheezon ko poojhte ho" },
    { number: 96, arabic: "وَٱللَّهُ خَلَقَكُمْ وَمَا تَعْمَلُونَ", transliteration: "WaAllahu khalaqakum wama taAAmaloona", transliterationB: "Wallaahu khalaqakum wa maa ta'maloon", english: "But Allah has created you and your handwork", romanUrdu: "Halaanke Allah hi ne tumko bhi paida kiya hai aur un cheezon ko bhi jinhein tum banatey ho”" },
    { number: 97, arabic: "قَالُوا۟ ٱبْنُوا۟ لَهُۥ بُنْيَٰنًۭا فَأَلْقُوهُ فِى ٱلْجَحِيمِ", transliteration: "Qaloo ibnoo lahu bunyanan faalqoohu fee aljaheemi", transliterationB: "Qaalub noo lahoo bun yaanan fa alqoohu fil jaheem", english: "They said, \"Build him a furnace, and throw him into the blazing fire", romanUrdu: "Unhon ne aapas mein kaha “ iske liya ek alaaw (pyre) tayyar karo aur isey dehakti hui aag ke dhair mein phenk do”" },
    { number: 98, arabic: "فَأَرَادُوا۟ بِهِۦ كَيْدًۭا فَجَعَلْنَٰهُمُ ٱلْأَسْفَلِينَ", transliteration: "Faaradoo bihi kaydan fajaAAalnahumu alasfaleena", transliterationB: "Fa araadoo bihee kaidan faja 'alnaahumul asfaleen", english: "(This failing), they then sought a stratagem against him, but We made them the ones most humiliated", romanUrdu: "Unhon ne uske khilaf ek karawayi karna chahi thi, magar humne unhi ko nicha dikha diya" },
    { number: 99, arabic: "وَقَالَ إِنِّى ذَاهِبٌ إِلَىٰ رَبِّى سَيَهْدِينِ", transliteration: "Waqala innee thahibun ila rabbee sayahdeeni", transliterationB: "Wa qaala innee zaahibun ilaa Rabbee sa yahdeen", english: "He said: \"I will go to my Lord! He will surely guide me", romanUrdu: "Ibrahim ne kaha “ main apne Rubb ki taraf jata hoon, wahi meri rehnumayi karega" },
    { number: 100, arabic: "رَبِّ هَبْ لِى مِنَ ٱلصَّٰلِحِينَ", transliteration: "Rabbi hab lee mina alssaliheena", transliterationB: "Rabbi hab lee minas saaliheen", english: "O my Lord! Grant me a righteous (son)", romanUrdu: "Aey parwardigar , mujhey ek beta ata kar jo salihon (righteous) mein se ho”" },
    { number: 101, arabic: "فَبَشَّرْنَٰهُ بِغُلَٰمٍ حَلِيمٍۢ", transliteration: "Fabashsharnahu bighulamin haleemin", transliterationB: "Fabashsharnaahu bighulaamin haleem", english: "So We gave him the good news of a boy ready to suffer and forbear", romanUrdu: "(Is dua ke jawab mein)humne usko ek haleem (burdbaar) ladke ki basharat di" },
    { number: 102, arabic: "فَلَمَّا بَلَغَ مَعَهُ ٱلسَّعْىَ قَالَ يَٰبُنَىَّ إِنِّىٓ أَرَىٰ فِى ٱلْمَنَامِ أَنِّىٓ أَذْبَحُكَ فَٱنظُرْ مَاذَا تَرَىٰ ۚ قَالَ يَٰٓأَبَتِ ٱفْعَلْ مَا تُؤْمَرُ ۖ سَتَجِدُنِىٓ إِن شَآءَ ٱللَّهُ مِنَ ٱلصَّٰبِرِينَ", transliteration: "Falamma balagha maAAahu alssaAAya qala ya bunayya innee ara fee almanami annee athbahuka faonthur matha tara qala ya abati ifAAal ma tumaru satajidunee in shaa Allahu mina alssabireena", transliterationB: "Falamma balagha ma'a hus sa'ya qaala yaa buniya inneee araa fil manaami anneee azbahuka fanzur maazaa taraa; qaala yaaa abatif 'al maa tu'maru satajidunee in shaaa'allaahu minas saabireen", english: "Then, when (the son) reached (the age of) (serious) work with him, he said: \"O my son! I see in vision that I offer thee in sacrifice: Now see what is thy view!\" (The son) said: \"O my father! Do as thou art commanded: thou will find me, if Allah so wills one practising Patience and Constancy", romanUrdu: "Woh ladka jab uske saath daud dhoop karne ki umar ko pahunch gaya to ( ek roz) Ibrahim ne ussey kaha, “beta, main khwab mein dekhta hoon ke main tujhey zibaah kar raha hoon, ab tu bata, tera kya khayal hai?” usne kaha, “abbajan , jo kuch aapko hukum diya jaa raha hai usey kar daliye, aap insha Allah mujhey saabiron(sabr karne walon) mein se payenge”" },
    { number: 103, arabic: "فَلَمَّآ أَسْلَمَا وَتَلَّهُۥ لِلْجَبِينِ", transliteration: "Falamma aslama watallahu liljabeeni", transliterationB: "Falammaaa aslamaa wa tallahoo liljabeen", english: "So when they had both submitted their wills (to Allah), and he had laid him prostrate on his forehead (for sacrifice)", romanUrdu: "Aakhir ko jab in dono ne sar-e-tasleem kham kardiya aur Ibrahim ne bete ko maathay ke bal gira diya" },
    { number: 104, arabic: "وَنَٰدَيْنَٰهُ أَن يَٰٓإِبْرَٰهِيمُ", transliteration: "Wanadaynahu an ya ibraheemu", transliterationB: "Wa naadainaahu ai yaaaa Ibraheem", english: "We called out to him \"O Abraham", romanUrdu: "Aur humne nida di ke “Aey Ibrahim" },
    { number: 105, arabic: "قَدْ صَدَّقْتَ ٱلرُّءْيَآ ۚ إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Qad saddaqta alrruya inna kathalika najzee almuhsineena", transliterationB: "Qad saddaqtar ru'yaa; innaa kazaalika najzil muhsineen", english: "Thou hast already fulfilled the vision!\" - thus indeed do We reward those who do right", romanUrdu: "Tu nay khwab sach kar dikhaya hum neki karne walon ko aisi hi jaza deta hain" },
    { number: 106, arabic: "إِنَّ هَٰذَا لَهُوَ ٱلْبَلَٰٓؤُا۟ ٱلْمُبِينُ", transliteration: "Inna hatha lahuwa albalao almubeenu", transliterationB: "Inna haazaa lahuwal balaaa'ul mubeen", english: "For this was obviously a trial", romanUrdu: "Yaqeenan yeh ek khuli aazmaaish thi”" },
    { number: 107, arabic: "وَفَدَيْنَٰهُ بِذِبْحٍ عَظِيمٍۢ", transliteration: "Wafadaynahu bithibhin AAatheemin", transliterationB: "Wa fadainaahu bizibhin 'azeem", english: "And We ransomed him with a momentous sacrifice", romanUrdu: "Aur humne ek badi qurbani fidiye mein de kar us bacchey ko chuda liya" },
    { number: 108, arabic: "وَتَرَكْنَا عَلَيْهِ فِى ٱلْءَاخِرِينَ", transliteration: "Watarakna AAalayhi fee alakhireena", transliterationB: "Wa taraknaa 'alaihi fil aakhireen", english: "And We left (this blessing) for him among generations (to come) in later times", romanUrdu: "Aur uski taarif o tauseef hamesha ke liye baad ki nasalon mein chodh di" },
    { number: 109, arabic: "سَلَٰمٌ عَلَىٰٓ إِبْرَٰهِيمَ", transliteration: "Salamun AAala ibraheema", transliterationB: "Salaamun 'alaaa Ibraaheem", english: "Peace and salutation to Abraham", romanUrdu: "Salaam hai Ibrahim par" },
    { number: 110, arabic: "كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Kathalika najzee almuhsineena", transliterationB: "Kazaalika najzil muhsineen", english: "Thus indeed do We reward those who do right", romanUrdu: "Hum neki karne waalon ko aisi hi jaza detay hain" },
    { number: 111, arabic: "إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ", transliteration: "Innahu min AAibadina almumineena", transliterationB: "Innahoo min 'ibaadinal mu'mineen", english: "For he was one of our believing Servants", romanUrdu: "Yaqeenan woh hamare momin bandon mein se tha" },
    { number: 112, arabic: "وَبَشَّرْنَٰهُ بِإِسْحَٰقَ نَبِيًّۭا مِّنَ ٱلصَّٰلِحِينَ", transliteration: "Wabashsharnahu biishaqa nabiyyan mina alssaliheena", transliterationB: "Wa bashsharnaahu bi Ishaaqa Nabiyayam minas saaliheen", english: "And We gave him the good news of Isaac - a prophet,- one of the Righteous", romanUrdu: "Aur humne usey Ishaq(Issac) ki basharat di , ek Nabi saliheen mein se" },
    { number: 113, arabic: "وَبَٰرَكْنَا عَلَيْهِ وَعَلَىٰٓ إِسْحَٰقَ ۚ وَمِن ذُرِّيَّتِهِمَا مُحْسِنٌۭ وَظَالِمٌۭ لِّنَفْسِهِۦ مُبِينٌۭ", transliteration: "Wabarakna AAalayhi waAAala ishaqa wamin thurriyyatihima muhsinun wathalimun linafsihi mubeenun", transliterationB: "Wa baaraknaa 'alaihi wa 'alaaa Ishaaq; wa min zurriyya tihimaa muhsinunw wa zaalimul linafshihee mubeen", english: "We blessed him and Isaac: but of their progeny are (some) that do right, and (some) that obviously do wrong, to their own souls", romanUrdu: "Aur usey aur Ishaq ko barakat di. Ab in dono ki zurriyat mein se koi mohsin hai aur koi apne nafs par sareeh zulm karne wala hai" },
    { number: 114, arabic: "وَلَقَدْ مَنَنَّا عَلَىٰ مُوسَىٰ وَهَٰرُونَ", transliteration: "Walaqad mananna AAala moosa waharoona", transliterationB: "Wa laqad mananna alaa Moosaa wa Haaroon", english: "Again (of old) We bestowed Our favour on Moses and Aaron", romanUrdu: "Aur humne Moosa o Haroon par ehsan kiya" },
    { number: 115, arabic: "وَنَجَّيْنَٰهُمَا وَقَوْمَهُمَا مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ", transliteration: "Wanajjaynahuma waqawmahuma mina alkarbi alAAatheemi", transliterationB: "Wa najjainaahumaa wa qawmahumaa minal karbil 'azeem", english: "And We delivered them and their people from (their) Great Calamity", romanUrdu: "Unko aur unki qaum ko karb-e-azeem( badi museebat) se nijaat di" },
    { number: 116, arabic: "وَنَصَرْنَٰهُمْ فَكَانُوا۟ هُمُ ٱلْغَٰلِبِينَ", transliteration: "Wanasarnahum fakanoo humu alghalibeena", transliterationB: "Wa nasarnaahum fakaanoo humul ghaalibeen", english: "And We helped them, so they overcame (their troubles)", romanUrdu: "Unhein nusrat bakshi jiski wajah se wahi galib rahey" },
    { number: 117, arabic: "وَءَاتَيْنَٰهُمَا ٱلْكِتَٰبَ ٱلْمُسْتَبِينَ", transliteration: "Waataynahuma alkitaba almustabeena", transliterationB: "Wa aatainaahumal Kitaabal mustabeen", english: "And We gave them the Book which helps to make things clear", romanUrdu: "Unko nihayat wazeh kitaab ata ki" },
    { number: 118, arabic: "وَهَدَيْنَٰهُمَا ٱلصِّرَٰطَ ٱلْمُسْتَقِيمَ", transliteration: "Wahadaynahuma alssirata almustaqeema", transliterationB: "Wa hadainaahumus Siraatal Mustaqeem", english: "And We guided them to the Straight Way", romanUrdu: "Unhein raah-e-raast dikhayi" },
    { number: 119, arabic: "وَتَرَكْنَا عَلَيْهِمَا فِى ٱلْءَاخِرِينَ", transliteration: "Watarakna AAalayhima fee alakhireena", transliterationB: "Wa taraknaa 'alaihimaa fil aakhireen", english: "And We left (this blessing) for them among generations (to come) in later times", romanUrdu: "Aur baad ki nasalon mein unka zikr e khair baaqi rakkha" },
    { number: 120, arabic: "سَلَٰمٌ عَلَىٰ مُوسَىٰ وَهَٰرُونَ", transliteration: "Salamun AAala moosa waharoona", transliterationB: "Salaamun 'alaa Moosaa wa Haaroon", english: "Peace and salutation to Moses and Aaron", romanUrdu: "Salaam hai Mossa aur Haroon par" },
    { number: 121, arabic: "إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Inna kathalika najzee almuhsineena", transliterationB: "Innaa kazaalika najzil muhsineen", english: "Thus indeed do We reward those who do right", romanUrdu: "Hum neki karne walon ko aisi hi jaza detay hain" },
    { number: 122, arabic: "إِنَّهُمَا مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ", transliteration: "Innahuma min AAibadina almumineena", transliterationB: "Innahumaa min 'ibaadinal mu'mineen", english: "For they were two of our believing Servants", romanUrdu: "Dar haqeeqat woh hamare momin bandon mein se thay" },
    { number: 123, arabic: "وَإِنَّ إِلْيَاسَ لَمِنَ ٱلْمُرْسَلِينَ", transliteration: "Wainna ilyasa lamina almursaleena", transliterationB: "Wa inna Ilyaasa laminal mursaleen", english: "So also was Elias among those sent (by Us)", romanUrdu: "Aur Ilyas bhi yaqeenan mursaleen(messengers) mein se tha" },
    { number: 124, arabic: "إِذْ قَالَ لِقَوْمِهِۦٓ أَلَا تَتَّقُونَ", transliteration: "Ith qala liqawmihi ala tattaqoona", transliterationB: "Iz qaala liqawmiheee alaa tattaqoon", english: "Behold, he said to his people, \"Will ye not fear (Allah)", romanUrdu: "Yaad karo jab usne apni qaum se kaha tha ke “tum log darte nahin ho" },
    { number: 125, arabic: "أَتَدْعُونَ بَعْلًۭا وَتَذَرُونَ أَحْسَنَ ٱلْخَٰلِقِينَ", transliteration: "AtadAAoona baAAlan watatharoona ahsana alkhaliqeena", transliterationB: "Atad'oona Ba'lanw wa tazaroona ahsanal khaaliqeen", english: "Will ye call upon Baal and forsake the Best of Creators", romanUrdu: "Kya tum BAAL ko pukarte ho aur ahsanul khaliqeen ko chodh dete ho" },
    { number: 126, arabic: "ٱللَّهَ رَبَّكُمْ وَرَبَّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ", transliteration: "Allaha rabbakum warabba abaikumu alawwaleena", transliterationB: "Allaaha Rabbakum wa Rabba aabaaa'ikumul awwaleen", english: "Allah, your Lord and Cherisher and the Lord and Cherisher of your fathers of old", romanUrdu: "Us Allah ko jo tumhara aur tumhare agle pichle aaba o ajdaad ka Rubb hai?”" },
    { number: 127, arabic: "فَكَذَّبُوهُ فَإِنَّهُمْ لَمُحْضَرُونَ", transliteration: "Fakaththaboohu fainnahum lamuhdaroona", transliterationB: "Fakazzaboohu fa inna hum lamuhdaroon", english: "But they rejected him, and they will certainly be called up (for punishment)", romanUrdu: "Magar unhon ne usey jhutla diya, so ab yaqeenan woh saza ke liye pesh kiye janey waley hain" },
    { number: 128, arabic: "إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ", transliteration: "Illa AAibada Allahi almukhlaseena", transliterationB: "Illaa 'ibaadal laahil mukhlaseen", english: "Except the sincere and devoted Servants of Allah (among them)", romanUrdu: "Bajuz un bandagaan e khuda ke jinko khaalis karliya gaya tha" },
    { number: 129, arabic: "وَتَرَكْنَا عَلَيْهِ فِى ٱلْءَاخِرِينَ", transliteration: "Watarakna AAalayhi fee alakhireena", transliterationB: "Wa taraknaa 'alaihi fil aakhireen", english: "And We left (this blessing) for him among generations (to come) in later times", romanUrdu: "Aur Ilyas ka zikr e khair humne baad ki nasalon mein baaki rakkha" },
    { number: 130, arabic: "سَلَٰمٌ عَلَىٰٓ إِلْ يَاسِينَ", transliteration: "Salamun AAala il yaseena", transliterationB: "Salaamun 'alaaa Ilyaaseen", english: "Peace and salutation to such as Elias", romanUrdu: "Salaam hai Ilyas par" },
    { number: 131, arabic: "إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Inna kathalika najzee almuhsineena", transliterationB: "Innaa kazaalika najzil muhsineen", english: "Thus indeed do We reward those who do right", romanUrdu: "Hum neki karne walon ko aisi hi jaza dete hain" },
    { number: 132, arabic: "إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ", transliteration: "Innahu min AAibadina almumineena", transliterationB: "Innahoo min 'ibaadinal mu'mineen", english: "For he was one of our believing Servants", romanUrdu: "Waqayi wo hamare momin bandon mein se tha" },
    { number: 133, arabic: "وَإِنَّ لُوطًۭا لَّمِنَ ٱلْمُرْسَلِينَ", transliteration: "Wainna lootan lamina almursaleena", transliterationB: "Wa inna Lootal laminal mursaleen", english: "So also was Lut among those sent (by Us)", romanUrdu: "Aur Lut bhi unhi logon mein se tha jo Rasool bana kar bheje gaye hain" },
    { number: 134, arabic: "إِذْ نَجَّيْنَٰهُ وَأَهْلَهُۥٓ أَجْمَعِينَ", transliteration: "Ith najjaynahu waahlahu ajmaAAeena", transliterationB: "Iz najjainaahu wa ahlahooo ajma'een", english: "Behold, We delivered him and his adherents, all", romanUrdu: "Yaad karo jab humne usko aur uske sab gar walon ko nijaat di" },
    { number: 135, arabic: "إِلَّا عَجُوزًۭا فِى ٱلْغَٰبِرِينَ", transliteration: "Illa AAajoozan fee alghabireena", transliterationB: "Illaa 'ajoozan fil ghaabireen", english: "Except an old woman who was among those who lagged behind", romanUrdu: "Siwaye ek budiya ke jo peechey reh janey walon mein se thi" },
    { number: 136, arabic: "ثُمَّ دَمَّرْنَا ٱلْءَاخَرِينَ", transliteration: "Thumma dammarna alakhareena", transliterationB: "Summa dammarnal aakhareen", english: "Then We destroyed the rest", romanUrdu: "Phir baaki sabko tehas nehas kardiya" },
    { number: 137, arabic: "وَإِنَّكُمْ لَتَمُرُّونَ عَلَيْهِم مُّصْبِحِينَ", transliteration: "Wainnakum latamurroona AAalayhim musbiheena", transliterationB: "Wa innakum latamurroona 'alaihim musbiheen", english: "Verily, ye pass by their (sites), by day", romanUrdu: "Aaj tum shab-o-roz unke ujday dayar (desolate habitations) par se guzarte ho" },
    { number: 138, arabic: "وَبِٱلَّيْلِ ۗ أَفَلَا تَعْقِلُونَ", transliteration: "Wabiallayli afala taAAqiloona", transliterationB: "Wa billail; afalaa ta'qiloon", english: "And by night: will ye not understand", romanUrdu: "Kya tumko aqal nahin aati" },
    { number: 139, arabic: "وَإِنَّ يُونُسَ لَمِنَ ٱلْمُرْسَلِينَ", transliteration: "Wainna yoonusa lamina almursaleena", transliterationB: "Wa inna Yoonusa laminal mursaleen", english: "So also was Jonah among those sent (by Us)", romanUrdu: "Aur yaqeenan Yunus bhi Rasoolon mein se tha" },
    { number: 140, arabic: "إِذْ أَبَقَ إِلَى ٱلْفُلْكِ ٱلْمَشْحُونِ", transliteration: "Ith abaqa ila alfulki almashhooni", transliterationB: "Iz abaqa ilal fulkil mash hoon", english: "When he ran away (like a slave from captivity) to the ship (fully) laden", romanUrdu: "Yaad karo jab woh ek bhari kashti ki taraf bhaag nikla" },
    { number: 141, arabic: "فَسَاهَمَ فَكَانَ مِنَ ٱلْمُدْحَضِينَ", transliteration: "Fasahama fakana mina almudhadeena", transliterationB: "Fasaahama fakaana minal mudhadeen", english: "He (agreed to) cast lots, and he was condemned", romanUrdu: "Phir quora andazi (cast lots) mein shareek hua aur usmein maath khayi (among the losers)" },
    { number: 142, arabic: "فَٱلْتَقَمَهُ ٱلْحُوتُ وَهُوَ مُلِيمٌۭ", transliteration: "Failtaqamahu alhootu wahuwa muleemun", transliterationB: "Faltaqamahul hootu wa huwa muleem", english: "Then the big Fish did swallow him, and he had done acts worthy of blame", romanUrdu: "Aakhir e kaar machli ne usey nigal liya aur woh malamat zada tha" },
    { number: 143, arabic: "فَلَوْلَآ أَنَّهُۥ كَانَ مِنَ ٱلْمُسَبِّحِينَ", transliteration: "Falawla annahu kana mina almusabbiheena", transliterationB: "Falaw laaa annahoo kaana minal musabbiheen", english: "Had it not been that he (repented and) glorified Allah", romanUrdu: "Ab agar woh tasbeeh karne walon mein se na hota to" },
    { number: 144, arabic: "لَلَبِثَ فِى بَطْنِهِۦٓ إِلَىٰ يَوْمِ يُبْعَثُونَ", transliteration: "Lalabitha fee batnihi ila yawmi yubAAathoona", transliterationB: "Lalabisa fee batniheee ilaa Yawmi yub'asoon", english: "He would certainly have remained inside the Fish till the Day of Resurrection", romanUrdu: "Roz-e-qayamat tak usi machli ke pait mein rehta" },
    { number: 145, arabic: "۞ فَنَبَذْنَٰهُ بِٱلْعَرَآءِ وَهُوَ سَقِيمٌۭ", transliteration: "Fanabathnahu bialAAarai wahuwa saqeemun", transliterationB: "Fanabaznaahu bil'araaa'i wa huwa saqeem", english: "But We cast him forth on the naked shore in a state of sickness", romanUrdu: "Aakhir humne usey badi sakheem (bimar /ill) halat mein ek chatiyal zameen par phenk diya" },
    { number: 146, arabic: "وَأَنۢبَتْنَا عَلَيْهِ شَجَرَةًۭ مِّن يَقْطِينٍۢ", transliteration: "Waanbatna AAalayhi shajaratan min yaqteenin", transliterationB: "Wa ambatnaa 'alaihi shajaratam mai yaqteen", english: "And We caused to grow, over him, a spreading plant of the gourd kind", romanUrdu: "Aur uspar ek bail-daar darakht (a spreading plant of the gourd kind) uga diya" },
    { number: 147, arabic: "وَأَرْسَلْنَٰهُ إِلَىٰ مِا۟ئَةِ أَلْفٍ أَوْ يَزِيدُونَ", transliteration: "Waarsalnahu ila miati alfin aw yazeedoona", transliterationB: "Wa arsalnaahu ilaa mi'ati alfin aw yazeedoon", english: "And We sent him (on a mission) to a hundred thousand (men) or more", romanUrdu: "Iske baad humne usey ek lakh ya us sey zayad logon ki taraf bheja" },
    { number: 148, arabic: "فَـَٔامَنُوا۟ فَمَتَّعْنَٰهُمْ إِلَىٰ حِينٍۢ", transliteration: "Faamanoo famattaAAnahum ila heenin", transliterationB: "Fa aamanoo famatta' naahum ilaa heen", english: "And they believed; so We permitted them to enjoy (their life) for a while", romanUrdu: "Woh imaan laye aur humne ek waqt e khaas tak unhein baaqi rakkha" },
    { number: 149, arabic: "فَٱسْتَفْتِهِمْ أَلِرَبِّكَ ٱلْبَنَاتُ وَلَهُمُ ٱلْبَنُونَ", transliteration: "Faistaftihim alirabbika albanatu walahumu albanoona", transliterationB: "Fastaftihim ali Rabbikal banaatu wa lahumul banoon", english: "Now ask them their opinion: Is it that thy Lord has (only) daughters, and they have sons", romanUrdu: "Phir zara in logon se pucho, kya (inke dil ko yeh baat lagti hai ke) tumhare Rubb ke liye to hon betiyan aur inke liye hon betay" },
    { number: 150, arabic: "أَمْ خَلَقْنَا ٱلْمَلَٰٓئِكَةَ إِنَٰثًۭا وَهُمْ شَٰهِدُونَ", transliteration: "Am khalaqna almalaikata inathan wahum shahidoona", transliterationB: "Am khalaqnal malaaa'i kata inaasanw wa hm shaahidoon", english: "Or that We created the angels female, and they are witnesses (thereto)", romanUrdu: "Kya waqayi humne malaika (farishton) ko auratein banaya hai aur yeh aankhon dekhi baat keh rahey hain" },
    { number: 151, arabic: "أَلَآ إِنَّهُم مِّنْ إِفْكِهِمْ لَيَقُولُونَ", transliteration: "Ala innahum min ifkihim layaqooloona", transliterationB: "Alaaa innahum min ifkihim la yaqooloon", english: "Is it not that they say, from their own invention", romanUrdu: "Khoob sun rakkho, dar-asal yeh log apni mann ghadat se yeh baat kehte hain" },
    { number: 152, arabic: "وَلَدَ ٱللَّهُ وَإِنَّهُمْ لَكَٰذِبُونَ", transliteration: "Walada Allahu wainnahum lakathiboona", transliterationB: "Waladal laahu wa innhum lakaaziboon", english: "Allah has begotten children\"? but they are liars", romanUrdu: "Ke Allah aulad rakhta hai, aur fil waqayi yeh jhootey hain" },
    { number: 153, arabic: "أَصْطَفَى ٱلْبَنَاتِ عَلَى ٱلْبَنِينَ", transliteration: "Astafa albanati AAala albaneena", transliterationB: "Astafal banaati 'alal baneen", english: "Did He (then) choose daughters rather than sons", romanUrdu: "Kya Allah ne beton ke bajaye betiyan apne liye pasand karli" },
    { number: 154, arabic: "مَا لَكُمْ كَيْفَ تَحْكُمُونَ", transliteration: "Ma lakum kayfa tahkumoona", transliterationB: "Maa lakum kaifa tahkumoon", english: "What is the matter with you? How judge ye", romanUrdu: "Tumhein kya ho gaya hai, kaise hukum laga rahey ho" },
    { number: 155, arabic: "أَفَلَا تَذَكَّرُونَ", transliteration: "Afala tathakkaroona", transliterationB: "Afalaa tazakkaroon", english: "Will ye not then receive admonition", romanUrdu: "Kya tumhein hosh nahin aata" },
    { number: 156, arabic: "أَمْ لَكُمْ سُلْطَٰنٌۭ مُّبِينٌۭ", transliteration: "Am lakum sultanun mubeenun", transliterationB: "Am lakum sultaanum mubeen", english: "Or have ye an authority manifest", romanUrdu: "Ya phir tumhare paas apni in baaton ke liye koi saaf sanad (daleel) hai" },
    { number: 157, arabic: "فَأْتُوا۟ بِكِتَٰبِكُمْ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Fatoo bikitabikum in kuntum sadiqeena", transliterationB: "Faatoo bi Kitaabikum in kuntum saadiqeen", english: "Then bring ye your Book (of authority) if ye be truthful", romanUrdu: "To lao apni woh kitaab agar tum sachhey ho" },
    { number: 158, arabic: "وَجَعَلُوا۟ بَيْنَهُۥ وَبَيْنَ ٱلْجِنَّةِ نَسَبًۭا ۚ وَلَقَدْ عَلِمَتِ ٱلْجِنَّةُ إِنَّهُمْ لَمُحْضَرُونَ", transliteration: "WajaAAaloo baynahu wabayna aljinnati nasaban walaqad AAalimati aljinnatu innahum lamuhdaroona", transliterationB: "Wa ja'aloo bainahoo wa bainal jinnati nasabaa; wa laqad 'alimatil jinnatu innahum lamuhdaroon", english: "And they have invented a blood-relationship between Him and the Jinns: but the Jinns know (quite well) that they have indeed to appear (before his Judgment-Seat)", romanUrdu: "Inhon ne Allah aur malaika ke darmiyan nasab (kinship)ka rishta bana rakkha hai, halanke malaika khoob jaante hain ke yeh log mujrim ki haisiyat se pesh honay waley hain" },
    { number: 159, arabic: "سُبْحَٰنَ ٱللَّهِ عَمَّا يَصِفُونَ", transliteration: "Subhana Allahi AAamma yasifoona", transliterationB: "Subhaanal laahi 'ammaa yasifoon", english: "Glory to Allah! (He is free) from the things they ascribe (to Him)", romanUrdu: "(aur woh kehte hain ke) “Allah un sifaat se paak hai" },
    { number: 160, arabic: "إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ", transliteration: "Illa AAibada Allahi almukhlaseena", transliterationB: "Illaa 'ibaadal laahil mukhlaseen", english: "Not (so do) the Servants of Allah, sincere and devoted", romanUrdu: "Jo uske khaalis bandon ke siwa dusre log uski taraf mansoob karte hain" },
    { number: 161, arabic: "فَإِنَّكُمْ وَمَا تَعْبُدُونَ", transliteration: "Fainnakum wama taAAbudoona", transliterationB: "Fa innakum wa maa ta'ubdoon", english: "For, verily, neither ye nor those ye worship", romanUrdu: "Pas tum aur tumhare yeh mabood" },
    { number: 162, arabic: "مَآ أَنتُمْ عَلَيْهِ بِفَٰتِنِينَ", transliteration: "Ma antum AAalayhi bifatineena", transliterationB: "Maaa antum 'alaihi befaaatineen", english: "Can lead (any) into temptation concerning Allah", romanUrdu: "Allah se kisi ko pher nahin sakte" },
    { number: 163, arabic: "إِلَّا مَنْ هُوَ صَالِ ٱلْجَحِيمِ", transliteration: "Illa man huwa sali aljaheemi", transliterationB: "Illaa man huwa saalil jaheem", english: "Except such as are (themselves) going to the blazing Fire", romanUrdu: "Magar sifr usko jo dozakh ki bhadakti hui aag mein jhulasne wala ho" },
    { number: 164, arabic: "وَمَا مِنَّآ إِلَّا لَهُۥ مَقَامٌۭ مَّعْلُومٌۭ", transliteration: "Wama minna illa lahu maqamun maAAloomun", transliterationB: "Wa maa minnasa illaa lahoo maqaamum ma'loom", english: "(Those ranged in ranks say): \"Not one of us but has a place appointed", romanUrdu: "Aur hamara haal to yeh hai ke hum mein se har ek ka ek muqaam mukarrar hai" },
    { number: 165, arabic: "وَإِنَّا لَنَحْنُ ٱلصَّآفُّونَ", transliteration: "Wainna lanahnu alssaffoona", transliterationB: "Wa innaa llanah nus saaffoon", english: "And we are verily ranged in ranks (for service)", romanUrdu: "Aur hum saff basta (in rows) khidmatgaar hain" },
    { number: 166, arabic: "وَإِنَّا لَنَحْنُ ٱلْمُسَبِّحُونَ", transliteration: "Wainna lanahnu almusabbihoona", transliterationB: "Wa innaa lanah nul musabbihoon", english: "And we are verily those who declare (Allah's) glory", romanUrdu: "Tasbeeh karne waley hain.”" },
    { number: 167, arabic: "وَإِن كَانُوا۟ لَيَقُولُونَ", transliteration: "Wain kanoo layaqooloona", transliterationB: "Wa in kaanoo la yaqooloon", english: "And there were those who said", romanUrdu: "Yeh log pehle to kaha karte thay" },
    { number: 168, arabic: "لَوْ أَنَّ عِندَنَا ذِكْرًۭا مِّنَ ٱلْأَوَّلِينَ", transliteration: "Law anna AAindana thikran mina alawwaleena", transliterationB: "Law anna 'indana zikram minal awwaleen", english: "If only we had had before us a Message from those of old", romanUrdu: "Ke kaash hamare paas woh “Zikr” hota jo pichli qaumon ko mila tha" },
    { number: 169, arabic: "لَكُنَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ", transliteration: "Lakunna AAibada Allahi almukhlaseena", transliterationB: "Lakunna 'ibaadal laahil mukhlaseen", english: "We should certainly have been Servants of Allah, sincere (and devoted)", romanUrdu: "To hum Allah ke cheedah (chune huey/chosen) banday hotay" },
    { number: 170, arabic: "فَكَفَرُوا۟ بِهِۦ ۖ فَسَوْفَ يَعْلَمُونَ", transliteration: "Fakafaroo bihi fasawfa yaAAlamoona", transliterationB: "Fakafaroo bihee fasawfa ya'lamoon", english: "But (now that the Qur'an has come), they reject it: But soon will they know", romanUrdu: "Magar (jab woh aa gaya) to inhon ne uska inkar kardiya, ab ankareeb inhein (is rawish ka natija) maloom ho jayega" },
    { number: 171, arabic: "وَلَقَدْ سَبَقَتْ كَلِمَتُنَا لِعِبَادِنَا ٱلْمُرْسَلِينَ", transliteration: "Walaqad sabaqat kalimatuna liAAibadina almursaleena", transliterationB: "Wa laqad sabaqat Kalimatunaa li'ibaadinal mursa leen", english: "Already has Our Word been passed before (this) to our Servants sent (by Us)", romanUrdu: "Apne bheje huey bandon se hum pehle hi waada kar chuke hain" },
    { number: 172, arabic: "إِنَّهُمْ لَهُمُ ٱلْمَنصُورُونَ", transliteration: "Innahum lahumu almansooroona", transliterationB: "Innaa hum lahumul mansooroon", english: "That they would certainly be assisted", romanUrdu: "Ke yaqeenan unki madad ki jayegi" },
    { number: 173, arabic: "وَإِنَّ جُندَنَا لَهُمُ ٱلْغَٰلِبُونَ", transliteration: "Wainna jundana lahumu alghaliboona", transliterationB: "Wa inna jundana lahumul ghaaliboon", english: "And that Our forces,- they surely must conquer", romanUrdu: "Aur hamara lashkar hi gaalib hokar rahega" },
    { number: 174, arabic: "فَتَوَلَّ عَنْهُمْ حَتَّىٰ حِينٍۢ", transliteration: "Fatawalla AAanhum hatta heenin", transliterationB: "Fatawalla 'anhum hatta heen", english: "So turn thou away from them for a little while", romanUrdu: "Pas (aey Nabi) zara kuch muddat tak inhein inke haal par chodh do" },
    { number: 175, arabic: "وَأَبْصِرْهُمْ فَسَوْفَ يُبْصِرُونَ", transliteration: "Waabsirhum fasawfa yubsiroona", transliterationB: "Wa absirhum fasawfa yubsiroon", english: "And watch them (how they fare), and they soon shall see (how thou farest)", romanUrdu: "Aur dekhte raho, anqareeb yeh khud bhi dekh lengey" },
    { number: 176, arabic: "أَفَبِعَذَابِنَا يَسْتَعْجِلُونَ", transliteration: "AfabiAAathabina yastaAAjiloona", transliterationB: "Afabi'azaabinaa yasta'jiloon", english: "Do they wish (indeed) to hurry on our Punishment", romanUrdu: "Kya yeh hamare azaab ke liye jaldi macha rahey hain" },
    { number: 177, arabic: "فَإِذَا نَزَلَ بِسَاحَتِهِمْ فَسَآءَ صَبَاحُ ٱلْمُنذَرِينَ", transliteration: "Faitha nazala bisahatihim fasaa sabahu almunthareena", transliterationB: "Fa izaa nazala bisaahatihim fasaaa'a sabaahul munzareen", english: "But when it descends into the open space before them, evil will be the morning for those who were warned (and heeded not)", romanUrdu: "Jab woh inke sehan (maidan/open space) mein aa utrega woh din un logon ke liye bahut bura hoga jinhein mutanabbeh (warn) kiya ja chuka hai" },
    { number: 178, arabic: "وَتَوَلَّ عَنْهُمْ حَتَّىٰ حِينٍۢ", transliteration: "Watawalla AAanhum hatta heenin", transliterationB: "Wa tawalla 'anhum hattaa heen", english: "So turn thou away from them for a little while", romanUrdu: "Pas zara inhein kuch muddat ke liye chodh do" },
    { number: 179, arabic: "وَأَبْصِرْ فَسَوْفَ يُبْصِرُونَ", transliteration: "Waabsir fasawfa yubsiroona", transliterationB: "Wa absir fasawfa yubsiroon", english: "And watch (how they fare) and they soon shall see (how thou farest)", romanUrdu: "Aur dekhte raho, anqareeb yeh khud dekh lenge" },
    { number: 180, arabic: "سُبْحَٰنَ رَبِّكَ رَبِّ ٱلْعِزَّةِ عَمَّا يَصِفُونَ", transliteration: "Subhana rabbika rabbi alAAizzati AAamma yasifoona", transliterationB: "Subhaana Rabbika Rabbil 'izzati 'amma yasifoon", english: "Glory to thy Lord, the Lord of Honour and Power! (He is free) from what they ascribe (to Him)", romanUrdu: "Paak hai tera Rubb, izzat ka maalik, un tamaam baaton se jo yeh log bana rahey hain" },
    { number: 181, arabic: "وَسَلَٰمٌ عَلَى ٱلْمُرْسَلِينَ", transliteration: "Wasalamun AAala almursaleena", transliterationB: "Wa salaamun 'alalmursaleen", english: "And Peace on the messengers", romanUrdu: "Aur salaam hai mursalin (messengers) par" },
    { number: 182, arabic: "وَٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Waalhamdu lillahi rabbi alAAalameena", transliterationB: "Walhamdu lillaahi Rabbil 'aalameen", english: "And Praise to Allah, the Lord and Cherisher of the Worlds", romanUrdu: "Aur saari taarif Allah Rabbul Aalameen hi ke liye hai" }
  ]
};
